css:
body { font-family: Arial, sans-serif; font-size: 10pt; color: #222; margin: 0; }
.oev-header { border-bottom: 2px solid #8B0000; padding: 10px 0; margin-bottom: 14px; }
.oev-company { font-size: 16pt; font-weight: bold; color: #8B0000; }
.oev-title { font-size: 13pt; font-weight: bold; text-align: right; color: #444; letter-spacing: 2px; }
.oev-meta { width: 100%; border-collapse: collapse; margin-bottom: 14px; }
.oev-meta td { padding: 6px 10px; vertical-align: top; border: 1px solid #ddd; }
.oev-meta .lbl { background: #faf6e8; font-weight: bold; width: 22%; color: #555; }
.oev-lines { width: 100%; border-collapse: collapse; margin: 14px 0; }
.oev-lines th { background: #8B0000; color: #fff; padding: 6px 8px; font-size: 9pt; text-align: left; }
.oev-lines td { padding: 6px 8px; border-bottom: 1px solid #eee; font-size: 9pt; vertical-align: top; }
.oev-lines td.r, .oev-lines th.r { text-align: right; }
.oev-totals { width: 50%; margin-left: 50%; border-collapse: collapse; margin-top: 6px; }
.oev-totals td { padding: 4px 10px; }
.oev-totals .lbl { font-weight: bold; text-align: right; color: #555; }
.oev-totals .val { text-align: right; width: 30%; }
.oev-totals .grand { border-top: 2px solid #8B0000; border-bottom: 2px solid #8B0000; font-weight: bold; font-size: 11pt; color: #8B0000; }
.oev-totals .balance { color: #c0392b; font-weight: bold; }
.oev-totals .paid { color: #2c7a3e; }
.oev-status-pill { display: inline-block; padding: 3px 12px; border-radius: 12px; font-weight: bold; font-size: 9pt; margin-right: 6px; }
.pill-approved { background: #d4edda; color: #155724; }
.pill-pending  { background: #fff3cd; color: #856404; }
.pill-rejected { background: #f8d7da; color: #721c24; }
.pill-paid     { background: #d4edda; color: #155724; }
.pill-partial  { background: #fff3cd; color: #856404; }
.pill-unpaid   { background: #f8d7da; color: #721c24; }
.pill-cancel   { background: #e2e3e5; color: #383d41; }
.oev-approval { width: 100%; border-collapse: collapse; margin: 18px 0; }
.oev-approval th { background: #faf6e8; padding: 6px 8px; font-size: 9pt; text-align: left; border: 1px solid #ddd; color: #555; }
.oev-approval td { padding: 6px 8px; font-size: 9pt; border: 1px solid #ddd; }
.oev-sign { width: 100%; margin-top: 40px; }
.oev-sign td { padding: 20px 10px 4px 10px; border-top: 1px dashed #888; font-size: 9pt; text-align: center; width: 33%; vertical-align: bottom; color: #555; }
.oev-footer { margin-top: 20px; font-size: 8pt; color: #999; text-align: center; }
@media print { body { margin: 0; } }
